mapper.select:
SELECT r.reception_id, r.reception_no, r.patient_id, p.name AS patient_name, r.visit_type, r.department_id, d.department_name AS department_name, r.doctor_id, doc.full_name AS doctor_name, r.reservation_id, r.scheduled_at, r.arrived_at, r.status, NVL(r.note, od.primary_symptom) AS note, NVL(r.is_active, 1) AS is_active, r.inactive_at, r.inactive_reason_code, r.inactive_reason_text, r.cancel_reason_code, r.cancel_reason_text, r.hold_reason_code, r.hold_reason_text, TO_NUMBER(REGEXP_SUBSTR(TRIM(r.created_by), '^[0-9]+$')) AS created_by, TO_NUMBER(REGEXP_SUBSTR(TRIM(r.updated_by), '^[0-9]+$')) AS updated_by, r.created_at, r.updated_at FROM RECEPTION r LEFT JOIN patient p ON p.patient_id = r.patient_id LEFT JOIN CMH.STAFF_DEPARTMENT d ON d.department_id = TO_CHAR(r.department_id) LEFT JOIN CMH.STAFF doc ON doc.staff_id = TO_CHAR(r.doctor_id) AND doc.staff_id LIKE 'DOC-%' AND UPPER(TRIM(NVL(doc.employment_status, 'ACTIVE'))) = 'ACTIVE' LEFT JOIN reception_outpatient_detail od ON od.reception_id = r.reception_id AND NVL(od.active_yn, 'Y') = 'Y'
AND r.reception_no = #{searchValue}
AND r.patient_id = #{searchValue}
AND p.name LIKE '%' || #{searchValue} || '%'
AND r.status = #{searchValue}
AND TRUNC(r.created_at) >= TO_DATE(#{dateFrom}, 'YYYY-MM-DD')
AND TRUNC(r.created_at) <= TO_DATE(#{dateTo}, 'YYYY-MM-DD')
AND TO_CHAR(r.department_id) = #{departmentId}
AND TO_CHAR(r.doctor_id) = #{doctorId}
ORDER BY r.reception_id

SELECT r.reception_id, r.reception_no, r.patient_id, p.name AS patient_name, r.visit_type, r.department_id, d.department_name AS department_name, r.doctor_id, doc.full_name AS doctor_name, r.reservation_id, r.scheduled_at, r.arrived_at, NVL(q.queue_status_cd, r.status) AS status, NVL(r.note, od.primary_symptom) AS note, NVL(r.is_active, 1) AS is_active, r.inactive_at, r.inactive_reason_code, r.inactive_reason_text, r.cancel_reason_code, r.cancel_reason_text, r.hold_reason_code, r.hold_reason_text, TO_NUMBER(REGEXP_SUBSTR(TRIM(r.created_by), '^[0-9]+$')) AS created_by, TO_NUMBER(REGEXP_SUBSTR(TRIM(r.updated_by), '^[0-9]+$')) AS updated_by, r.created_at, r.updated_at FROM RECEPTION_WAITING_QUEUE q INNER JOIN RECEPTION r ON r.reception_id = q.reception_id LEFT JOIN patient p ON p.patient_id = r.patient_id LEFT JOIN CMH.STAFF_DEPARTMENT d ON d.department_id = TO_CHAR(r.department_id) LEFT JOIN CMH.STAFF doc ON doc.staff_id = TO_CHAR(r.doctor_id) AND doc.staff_id LIKE 'DOC-%' AND UPPER(TRIM(NVL(doc.employment_status, 'ACTIVE'))) = 'ACTIVE' LEFT JOIN reception_outpatient_detail od ON od.reception_id = r.reception_id AND NVL(od.active_yn, 'Y') = 'Y'
q.queue_status_cd IN ('WAITING', 'CALLED') AND NVL(q.active_yn, 'Y') = 'Y'
AND TO_CHAR(r.department_id) = #{departmentId}
AND TO_CHAR(r.doctor_id) = #{doctorId}
AND TRUNC(r.created_at) = TO_DATE(#{date}, 'YYYY-MM-DD')
ORDER BY q.queue_order_no ASC, q.created_at ASC, r.reception_id ASC
